    miniChallenge: {
      type: "multipleChoice",
      question: "Arjun wants to watch a log file update in real-time as a deployment runs. Which command does he use?",
      options: [
        "cat app.log",
        "tail -f app.log",
        "grep app.log",
        "ls -la app.log"
      ],
      correctAnswer: "tail -f app.log",
      explanation: "The 'tail -f' command shows the last lines of a file and 'follows' it — printing new lines as they are written. This is the standard way to monitor live log output during deployments or debugging."
    }
