    miniChallenge: {
      type: "fillInBlank",
      question: "To copy a file in Python using the shutil module, use <code>shutil._____(source, destination)</code>.",
      correctAnswer: "copy",
      explanation: "shutil.copy(src, dst) copies a file from source to destination. shutil.copy2() also preserves metadata (timestamps). shutil.copytree() copies entire directory trees. shutil.move() moves (cut+paste) instead of copying. shutil.rmtree() deletes an entire directory tree."
    }
