function useModules(category) {
  return useQuery({
    queryKey: ["modules", category],
    queryFn: async () => {
      await new Promise((r) => setTimeout(r, 300));
      if (category) {
        return MOCK_MODULES.filter((m) => m.category === category);
      }
      return MOCK_MODULES;
    },
    staleTime: 1e3 * 60 * 5
  });
}
function useModule(id) {
  return useQuery({
    queryKey: ["module", id],
    queryFn: async () => {
      await new Promise((r) => setTimeout(r, 200));
      return MOCK_MODULES.find((m) => m.id === id);
    },
    enabled: !!id,
    staleTime: 1e3 * 60 * 5
  });
}
function useMarkModuleCompleted() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (moduleId) => {
      await new Promise((r) => setTimeout(r, 400));
      return moduleId;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["modules"] });
      queryClient.invalidateQueries({ queryKey: ["progress"] });
    }
  });
}
function useModuleLessons(moduleId) {
  return ALL_LESSON_CONTENT[moduleId] ?? [];
}
export {
  useModule as a,
  useMarkModuleCompleted as b,
  useModuleLessons as c,
  useModules as u
};
